6: // Compare two character, ignore case. Caller must check both is alphabet before using this
7: // function.
8: fn ascii_equal_ignore_case(a: u8, b: u8) bool {
9:     return std.ascii.toLower(a) == std.ascii.toLower(b);
10: }
