193: const InputMode = enum(u8) {
194:     // By pass Vietnamese input processing and append the character as is.
195:     literal,
196:     // Process Vietnamese input in Telex input method.
197:     telex,
198: };
199: 
200: const State = struct {
201:     // The effective buffer to process Vietnamese input. we will skip processing if the buffer
202:     // longer than 16.
203:     buffer_effective: [16]Span,
204:     // The maximum buffer length that the engine still keeps the effective buffer, after the maximum
205:     // value (255), we will reset the effective buffer and this value.
206:     buffer_length: u8 = 0,
207:     // Mark the earliest position (inclusive) in buffer where we modified the span, will be used to
208:     // calculate backspaces and replacement characters.
209:     buffer_modification_index: ?u8 = null,
210:     // Mark the position (inclusive) in buffer where we will switch to literal mode (due to manually
211:     // switch, input cancellation, exceed effective buffer). This value is only used in .telex mode
212:     // and the engine is working on position on or after literal index, the engine will skip
213:     // Vietnamese input processing (we only count valid numbers, null mean no literal index).
214:     literal_index: ?u8 = null,
215:     // Determine if we will process input in the specified mode (Telex) or append the character as is.
216:     mode: InputMode = .literal,
217: 
218:     // Initialize the State on allocated memory.
219:     fn init(self: *State) void {
220:         self.* = .{
221:             .buffer_effective = undefined,
222:         };
223:     }
224: 
225:     fn add(self: *State, c: u8) void {
226:         // Only allow a-zA-Z.
227:         assert(std.ascii.isAlphabetic(c));
228: 
229:         // The buffer_modification index must be inbound of the buffer_effective.
230:         assert(self.buffer_modification_index == null or self.buffer_modification_index.? < self.buffer_effective.len);
231: 
232:         // Input mode must be either .literal or .telex.
233:         assert(self.mode == .literal or self.mode == .telex);
234: 
235:         // Should never set literal_index in .literal mode.
236:         if (self.mode == .literal) {
237:             assert(self.literal_index == null);
238:         }
239: 
240:         if (self.literal_index) |literal_index| {
241:             // When literal_index is set, mode must be .telex.
242:             assert(self.mode == .telex);
243:             // The literal_index value must be in range null or 0 -> 16 (buffer_effective length)
244:             // because we won't process Vietnamese input outside the buffer_effective.
245:             assert(literal_index <= self.buffer_effective.len);
246:             // The literal_index value must be less than buffer length.
247:             assert(literal_index < self.buffer_length);
248:         }
249: 
250:         switch (c) {
251:             'A', 'a' => {
252:                 if (self.literal_index != null or self.mode == .literal or self.buffer_length == 0) {
253:                     // 1. Enable literal input when literal_index is set or on literal mode. The
254:                     // literal_index is also set when the word starts with non-Vietnamese onsets.
255:                     // 2. Append literal because no previous span existed. Continue Vietnamese
256:                     // processing on next input.
257:                     self.append_literal(c);
258:                     // Set modification index to null because we didn't modify any existing span.
259:                     self.buffer_modification_index = null;
260:                 } else if (ascii_equal_ignore_case(self.buffer_effective[self.buffer_length - 1].base, c) and self.buffer_effective[self.buffer_length - 1].diacritic == .empty) {
261:                     // 3. Previous span is 'A' or 'a', apply circumflex.
262:                     const span_previous = self.buffer_effective[self.buffer_length - 1];
263:                     self.buffer_effective[self.buffer_length - 1] = Span.init_diacritic_tone(span_previous.base, .circumflex, span_previous.tone);
264:                     // Set modification index for calculating synthetic backspace.
265:                     self.buffer_modification_index = self.buffer_length - 1;
266:                 } else if (ascii_equal_ignore_case(self.buffer_effective[self.buffer_length - 1].base, c) and self.buffer_effective[self.buffer_length - 1].diacritic == .breve) {
267:                     // 4. Previous span is 'Ă' or 'ă', override to circumflex.
268:                     const span_previous = self.buffer_effective[self.buffer_length - 1];
269:                     self.buffer_effective[self.buffer_length - 1] = Span.init_diacritic_tone(span_previous.base, .circumflex, span_previous.tone);
270:                     // Set modification index for calculating synthetic backspace.
271:                     self.buffer_modification_index = self.buffer_length - 1;
272:                 } else if (ascii_equal_ignore_case(self.buffer_effective[self.buffer_length - 1].base, c) and self.buffer_effective[self.buffer_length - 1].diacritic == .circumflex) {
