414:     // Append literal character when possible. Then inclease the buffer_length.
415:     fn append_literal(self: *State, c: u8) void {
416:         // Only allow a-zA-Z.
417:         assert(std.ascii.isAlphabetic(c));
418: 
419:         // Check if we can add new span for input character.
420:         if (self.buffer_length < self.buffer_effective.len) {
421:             // Add character to span.
422:             self.buffer_effective[self.buffer_length] = Span.init(c);
423:         }
424:         // Increase the buffer length for tracking, we will need it went handling backspace.
425:         self.buffer_length = self.buffer_length + 1;
426:     }
427: 
428:     fn backspace(self: *State) void {
429:         // buffer_length must be positive for backspace.
430:         assert(self.buffer_length > 0);
431: 
432:         // Input mode must be either .literal or .telex.
433:         assert(self.mode == .literal or self.mode == .telex);
434: 
435:         if (self.literal_index) |literal_index| {
436:             // Input mode must be .telex when literal_index is set.
437:             assert(self.mode == .telex);
438:             // literal_index must be within buffer range when set.
439:             assert(literal_index < self.buffer_length);
440:         }
441: 
442:         // decrease the buffer_length to match the backspace.
443:         self.buffer_length -= 1;
444:         // because backspace doesn't retro-modify the buffer, unset the buffer_modification_index.
445:         self.buffer_modification_index = null;
446:         // if the literal_index is out of buffer range, unset it.
447:         if (self.literal_index != null and self.literal_index.? == self.buffer_length) {
448:             self.literal_index = null;
449:         }
450:     }
451: };
