208:     // calculate backspaces and replacement characters.
209:     buffer_modification_index: ?u8 = null,
210:     // Mark the position (inclusive) in buffer where we will switch to literal mode (due to manually
211:     // switch, input cancellation, exceed effective buffer). This value is only used in .telex mode
212:     // and the engine is working on position on or after literal index, the engine will skip
213:     // Vietnamese input processing (we only count valid numbers, null mean no literal index).
214:     literal_index: ?u8 = null,
215:     // Determine if we will process input in the specified mode (Telex) or append the character as is.
216:     mode: InputMode = .literal,
217: 
218:     // Initialize the State on allocated memory.
219:     fn init(self: *State) void {
220:         self.* = .{
