229:         // The buffer_modification index must be inbound of the buffer_effective.
230:         assert(self.buffer_modification_index == null or self.buffer_modification_index.? < self.buffer_effective.len);
231: 
232:         // Input mode must be either .literal or .telex.
233:         assert(self.mode == .literal or self.mode == .telex);
