241:             // When literal_index is set, mode must be .telex.
242:             assert(self.mode == .telex);
243:             // The literal_index value must be in range null or 0 -> 16 (buffer_effective length)
244:             // because we won't process Vietnamese input outside the buffer_effective.
245:             assert(literal_index <= self.buffer_effective.len);
